const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGO_URI = process.env.MONGO_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'queryservice';

let db;

async function connectToMongo() {
  const client = new MongoClient(MONGO_URI);
  await client.connect();
  db = client.db(DB_NAME);
  console.log('Connected to MongoDB');
  return client;
}

// Sanitize user input to prevent NoSQL injection
function sanitizeFilter(obj) {
  if (obj === null || obj === undefined) {
    return obj;
  }

  if (typeof obj === 'string' || typeof obj === 'number' || typeof obj === 'boolean') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => sanitizeFilter(item));
  }

  if (typeof obj === 'object') {
    const sanitized = {};
    const allowedOperators = new Set([
      '$gt', '$gte', '$lt', '$lte', '$eq', '$ne',
      '$in', '$nin', '$regex', '$options',
      '$exists', '$type',
      '$and', '$or', '$nor', '$not',
      '$elemMatch', '$size', '$all',
      '$mod', '$text', '$search', '$language',
      '$caseSensitive', '$diacriticSensitive'
    ]);

    // Block dangerous operators that could cause server-side code execution or data exfiltration
    const blockedOperators = new Set([
      '$where', '$accumulator', '$function',
      '$expr', '$jsonSchema',
      '$comment'
    ]);

    for (const key of Object.keys(obj)) {
      if (key.startsWith('$') && blockedOperators.has(key)) {
        throw new Error(`Operator "${key}" is not allowed for security reasons`);
      }

      if (key.startsWith('$') && !allowedOperators.has(key)) {
        throw new Error(`Operator "${key}" is not supported`);
      }

      sanitized[key] = sanitizeFilter(obj[key]);
    }

    return sanitized;
  }

  return obj;
}

// Convert special string patterns to proper types
function convertTypes(obj) {
  if (obj === null || obj === undefined) {
    return obj;
  }

  if (typeof obj === 'string') {
    // Convert ObjectId strings
    if (/^[0-9a-fA-F]{24}$/.test(obj)) {
      // Don't auto-convert, let it be explicit
      return obj;
    }
    return obj;
  }

  if (typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => convertTypes(item));
  }

  const converted = {};
  for (const [key, value] of Object.entries(obj)) {
    if (key === '_id' && typeof value === 'string' && /^[0-9a-fA-F]{24}$/.test(value)) {
      converted[key] = new ObjectId(value);
    } else if (key === '$oid' && typeof value === 'string') {
      return new ObjectId(value);
    } else if (key === '$date' && typeof value === 'string') {
      return new Date(value);
    } else {
      converted[key] = convertTypes(value);
    }
  }
  return converted;
}

// POST /api/:collection/find - Query documents with filters
app.post('/api/:collection/find', async (req, res) => {
  try {
    const { collection } = req.params;
    const {
      filter = {},
      projection = null,
      sort = null,
      limit = 100,
      skip = 0
    } = req.body;

    // Validate collection name to prevent accessing system collections
    if (collection.startsWith('system.') || collection.includes('$')) {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    // Enforce a maximum limit
    const safeLimit = Math.min(Math.max(parseInt(limit) || 100, 1), 1000);
    const safeSkip = Math.max(parseInt(skip) || 0, 0);

    // Sanitize and convert the filter
    const sanitizedFilter = sanitizeFilter(filter);
    const convertedFilter = convertTypes(sanitizedFilter);

    let cursor = db.collection(collection).find(convertedFilter);

    if (projection) {
      const sanitizedProjection = sanitizeFilter(projection);
      cursor = cursor.project(sanitizedProjection);
    }

    if (sort) {
      const sanitizedSort = sanitizeFilter(sort);
      cursor = cursor.sort(sanitizedSort);
    }

    cursor = cursor.skip(safeSkip).limit(safeLimit);

    const documents = await cursor.toArray();
    const totalCount = await db.collection(collection).countDocuments(convertedFilter);

    res.json({
      success: true,
      data: documents,
      metadata: {
        total: totalCount,
        limit: safeLimit,
        skip: safeSkip,
        returned: documents.length
      }
    });
  } catch (error) {
    console.error('Query error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

