// POST /api/:collection/aggregate - Run aggregation pipelines
app.post('/api/:collection/aggregate', async (req, res) => {
  try {
    const { collection } = req.params;
    const { pipeline = [] } = req.body;

    if (collection.startsWith('system.') || collection.includes('$')) {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    if (!Array.isArray(pipeline)) {
      return res.status(400).json({ error: 'Pipeline must be an array' });
    }

    // Block dangerous aggregation stages
    const blockedStages = new Set(['$out', '$merge', '$collStats', '$indexStats', '$planCacheStats', '$currentOp', '$listSessions']);
    for (const stage of pipeline) {
      const stageKey = Object.keys(stage)[0];
      if (blockedStages.has(stageKey)) {
        return res.status(400).json({ error: `Aggregation stage "${stageKey}" is not allowed` });
      }
    }

    // Enforce a $limit at the end if not present
    const hasLimit = pipeline.some(stage => '$limit' in stage);
    if (!hasLimit) {
      pipeline.push({ $limit: 1000 });
    }

    const sanitizedPipeline = pipeline.map(stage => sanitizeFilter(stage));
    const convertedPipeline = sanitizedPipeline.map(stage => convertTypes(stage));

    const results = await db.collection(collection).aggregate(convertedPipeline).toArray();

    res.json({
      success: true,
      data: results,
      metadata: {
        returned: results.length
      }
    });
  } catch (error) {
    console.error('Aggregation error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

